UPDATE public.questions SET
  stimulus_text = '• Turbine prototype 19 employs tubercle-inspired blade geometry modeled on humpback whale fins
• Field tests documented twelve-percent efficiency gains at moderate wind speeds
• Conventional flat-blade designs underperformed at identical wind speeds in controlled comparisons
• Overnight noise monitoring confirmed compliance with local residential ordinances',
  question_text = 'The student wants to emphasize the most empirically supported approach documented in the notes. Which choice most effectively synthesizes relevant information to accomplish this goal?',
  stimulus_type = 'passage',
  options = '[{"id":"A","text":"In intervention 19, structured pair discussion outperformed silent worksheets, producing a twelve-point comprehension gain linked to evidence-based classroom observations.","is_correct":true,"explanation":"Synthesizes the notes to highlight the approach associated with the largest measured gain and supporting teacher observations."},{"id":"B","text":"Whale-fin tubercles inspired numerous unrelated inventions that the notes never mention, evaluate, or compare methodologically.","is_correct":false,"explanation":"Imports information absent from the notes and fails to compare instructional methods on empirical grounds."},{"id":"C","text":"Worksheets remain the only pedagogically valid tool because they require silent individual focus regardless of measured outcome differences.","is_correct":false,"explanation":"Directly contradicted by the notes, which report substantially larger gains for discussion than for worksheets."},{"id":"D","text":"Comprehension scores are immutable when instructional methods vary within the same curricular unit and assessment window.","is_correct":false,"explanation":"Contradicted by reported score changes for both cohorts documented in the notes."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The notes compare two instructional approaches and report unequal gains favoring structured discussion. The passage anchors the correct choice in language such as "• Turbine prototype 19 employs tubercle-inspired blade geometry modeled on humpback whale fins • Fie…", which eliminates options that contradict or overreach that evidence. Choice A is correct because it aligns with the textual logic: x. Each incorrect option either contradicts an explicit detail, imports information absent from the stimulus, or answers a different question than the stem asks. On hard Digital SAT items, the best answer synthesizes multiple sentences rather than matching a single keyword in isolation.',
  difficulty = 'hard',
